$ErrorActionPreference = 'Stop'
$requestId = 'exec-20260509-wbs02-batch2-single-select-migration-001'
$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
$downloads = [Environment]::GetEnvironmentVariable('DCOIR_DOWNLOADS_DIR','Machine')
$baseId = [Environment]::GetEnvironmentVariable('DCOIR_AIRTABLE_BASE_ID','Machine')
$token = [Environment]::GetEnvironmentVariable('DCOIR_AIRTABLE_TOKEN','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { throw 'Missing DCOIR_REPO_ROOT' }
if ([string]::IsNullOrWhiteSpace($downloads)) { throw 'Missing DCOIR_DOWNLOADS_DIR' }
if ([string]::IsNullOrWhiteSpace($baseId)) { throw 'Missing DCOIR_AIRTABLE_BASE_ID' }
if ([string]::IsNullOrWhiteSpace($token)) { throw 'Missing DCOIR_AIRTABLE_TOKEN' }
$modulePath = Join-Path $repo 'operator_tools\github_desktop_lane\modules\Dcoir.AirtableBulkUpdate\Dcoir.AirtableBulkUpdate.psm1'
if (-not (Test-Path -LiteralPath $modulePath -PathType Leaf)) { throw "Missing bulk update module: $modulePath" }
Import-Module -Force $modulePath
$targetsList = New-Object System.Collections.Generic.List[object]
function Add-TargetGroup {
  param(
    [string]$TableId, [string]$TableName, [string]$FieldId, [string]$FieldName,
    [string]$OldChoiceName, [string]$OldChoiceId, [string]$NewChoiceName, [string]$NewChoiceId,
    [string[]]$RecordIds
  )
  foreach ($rid in $RecordIds) {
    $targetsList.Add([pscustomobject][ordered]@{
      table_id = $TableId; table_name = $TableName; record_id = $rid; display_key = $rid;
      field_id = $FieldId; field_name = $FieldName;
      old_choice_name = $OldChoiceName; old_choice_id = $OldChoiceId;
      new_choice_name = $NewChoiceName; new_choice_id = $NewChoiceId;
      approval_packet = 'WBS02 Batch2 row-level migration payload';
      approval_phrase = 'APPROVE EXECUTE WBS02 BATCH2 WRITE-READY SINGLE-SELECT MIGRATION PAYLOAD'
    }) | Out-Null
  }
}
