New-Item -ItemType Directory -Force -Path $outDir | Out-Null
$reportReadback = Join-Path $repo ('chatgpt_staging\status_reports\chatgpt-exec\' + $requestId + '\artifact_readback')
New-Item -ItemType Directory -Force -Path $reportReadback | Out-Null
$targets | ConvertTo-Json -Depth 40 | Out-File -LiteralPath (Join-Path $outDir 'approved_targets.json') -Encoding utf8
$targets | ConvertTo-Json -Depth 40 | Out-File -LiteralPath (Join-Path $reportReadback 'approved_targets.json') -Encoding utf8
$headers = @{ Authorization = ('Bearer ' + $token); 'Content-Type' = 'application/json' }
$result = Invoke-DcoirAirtableSelectAliasUpdateWithBeforeGates -BaseId $baseId -Headers $headers -TargetRecords $targets -BatchSize 10 -Typecast:$false
$result | ConvertTo-Json -Depth 100 | Out-File -LiteralPath (Join-Path $outDir 'execution_result.json') -Encoding utf8
$result | ConvertTo-Json -Depth 100 | Out-File -LiteralPath (Join-Path $reportReadback 'execution_result.json') -Encoding utf8
$result.before_readback | ConvertTo-Json -Depth 80 | Out-File -LiteralPath (Join-Path $reportReadback 'before_readback.json') -Encoding utf8
$result.after_readback | ConvertTo-Json -Depth 80 | Out-File -LiteralPath (Join-Path $reportReadback 'after_readback.json') -Encoding utf8
$result.planned_payload | ConvertTo-Json -Depth 80 | Out-File -LiteralPath (Join-Path $reportReadback 'planned_payload.json') -Encoding utf8
$summary = [ordered]@{ request_id = $requestId; result = [string]$result.result; expected_target_count = 42; input_count = [int]$result.input_count; updated_count = [int]$result.updated_count; after_mismatch_count = @($result.after_mismatches).Count; mutation_scope = 'single-select record updates only'; excluded_scope = @('Session Checkpoints checkpoint_status review-required rows','dcoir-validation-orchestrator multi-select row','schema mutation','select option deletion','Delete Queue') }
$summary | ConvertTo-Json -Depth 20 | Out-File -LiteralPath (Join-Path $outDir 'execution_summary.json') -Encoding utf8
$summary | ConvertTo-Json -Depth 20 | Out-File -LiteralPath (Join-Path $reportReadback 'execution_summary.json') -Encoding utf8
if ([string]$result.result -ne 'success') { throw ('Bulk update result was not success: ' + [string]$result.result) }
if ([int]$result.input_count -ne 42 -or [int]$result.updated_count -ne 42) { throw "Unexpected update count. Input=$($result.input_count) Updated=$($result.updated_count)" }
if (@($result.after_mismatches).Count -ne 0) { throw 'After-readback mismatches were reported.' }
$zipScript = Join-Path $repo 'operator_tools\github_desktop_lane\scripts\New-DcoirChatGPTFriendlyZip.ps1'
if (Test-Path -LiteralPath $zipScript -PathType Leaf) { & $zipScript -SourceFolder $outDir -OutputZip ($outDir + '.chatgpt.zip') -NormalizeTextEncoding | Out-Null }
$summary | ConvertTo-Json -Depth 20
